# Define tool for document retrieval
tools = [
    {
        "name": "retrieve_documents",
        "description": "Retrieve relevant documents from knowledge base",
        "input_schema": {
            "type": "object",
            "properties": {
                "query": {"type": "string"}
            }
        }
    }
]

# Claude calls tool when it needs knowledge
messages = [{"role": "user", "content": user_query}]
response = client.messages.create(
    model="claude-sonnet-4-20250514",
    messages=messages,
    tools=tools
)

# Use Claude as reranker
rerank_tool = {
    "name": "rerank_documents",
    "description": "Rerank documents by relevance to query",
    "input_schema": {
        "query": "string",
        "documents": "array of strings"
    }
}

# Define question-answering prompt
prompt = PromptTemplate.from_template(
    "Based on this context: {context}\nAnswer: {question}"
)

# Retrieve
def retrieve(state: State):
    retrieved_docs = vector_store.similarity_search(state["question"])
    return {"context": retrieved_docs}

# Generate
def generate(state: State):
    docs_content = "\n\n".join(doc.page_content for doc in state["context"])
    messages = prompt.invoke({
        "question": state["question"],
        "context": docs_content
    })
    response = llm.invoke(messages)
    return {"answer": response.content}
